package org.springframework.ai.aot;

import org.junit.jupiter.api.Tag;
import org.junit.jupiter.api.Test;
import org.springframework.aot.hint.TypeReference;

import static org.junit.jupiter.api.Assertions.*;

import java.util.Set;
import com.fasterxml.jackson.annotation.JsonInclude;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

class AiRuntimeHintsFindJsonAnnotatedClassesInPackageTest {
    private static final Logger log = LoggerFactory.getLogger(AiRuntimeHintsFindJsonAnnotatedClassesInPackageTest.class);

    @Test
    @Tag("valid")
    public void findAnnotatedClassesInValidPackage() {
        // Arrange
        String validPackageName = "org.springframework.ai.aot.models"; // Ensure this package exists and contains annotated classes
        // Act
        Set<TypeReference> result = AiRuntimeHints.findJsonAnnotatedClassesInPackage(validPackageName);
        // Assert
        assertNotNull(result, "Result should not be null.");
        assertTrue(result.stream().allMatch(typeRef -> 
            typeRef.getClassName().contains("JsonInclude")), 
            "All types should contain relevant Jackson annotations.");
    }

    @Test
    @Tag("invalid")
    public void findAnnotatedClassesInInvalidPackage() {
        // Arrange
        String invalidPackageName = "org.invalid.package"; // Corrected invalid package name syntax
        // Act
        Exception exception = assertThrows(RuntimeException.class, () -> 
            AiRuntimeHints.findJsonAnnotatedClassesInPackage(invalidPackageName));
        // Assert
        assertTrue(exception.getCause() instanceof ClassNotFoundException, 
            "Expected a RuntimeException due to invalid package.");
    }

    @Test
    @Tag("boundary")
    public void findAnnotatedClassesInEmptyPackage() {
        // Arrange
        String emptyPackageName = "org.empty.package"; // Corrected invalid package name syntax
        // Act
        Set<TypeReference> result = AiRuntimeHints.findJsonAnnotatedClassesInPackage(emptyPackageName);
        // Assert
        assertNotNull(result, "Result should not be null.");
        assertTrue(result.isEmpty(), "Expected no annotated classes for an empty package.");
    }

    @Test
    @Tag("boundary")
    public void findAnnotatedClassesWithNoMatchingTypes() {
        // Arrange
        String packageName = "org.springframework.ai.aot.nomatch"; // Corrected invalid syntax
        // Act
        Set<TypeReference> result = AiRuntimeHints.findJsonAnnotatedClassesInPackage(packageName);
        // Assert
        assertNotNull(result, "Result should not be null.");
        assertTrue(result.isEmpty(), "Expected no annotated classes.");
    }

    @Test
    @Tag("integration")
    public void findAnnotatedClassesInNestedPackages() {
        // Arrange
        String nestedPackageName = "org.springframework.ai.aot.nested"; // Ensure this package exists and contains nested annotated classes
        // Act
        Set<TypeReference> result = AiRuntimeHints.findJsonAnnotatedClassesInPackage(nestedPackageName);
        // Assert
        assertNotNull(result, "Result should not be null.");
        assertFalse(result.isEmpty(), "Expected annotated classes in nested package.");
    }
}
